import scala.util.Random
import java.time.{Instant, Duration}
import java.util.concurrent.ConcurrentHashMap
import scala.collection.concurrent
import scala.jdk.CollectionConverters._

case class SessionToken(
  token: String,
  userId: String,
  createdAt: Instant,
  expiresAt: Instant,
  isActive: Boolean = true
)

case class ApiKey(
  key: String,
  secret: String,
  owner: String,
  createdAt: Instant,
  expiresAt: Option[Instant] = None,
  isActive: Boolean = true
)

trait TokenGenerator {
  def generateToken(length: Int = 32): String
  def generateSessionToken(userId: String, durationMinutes: Long = 30): SessionToken
  def generateApiKey(owner: String, expiresInDays: Option[Long] = None): ApiKey
}

class DefaultTokenGenerator extends TokenGenerator {

  override def generateToken(length: Int = 32): String = {
    Random.alphanumeric.take(length).mkString
  }

  override def generateSessionToken(userId: String, durationMinutes: Long = 30): SessionToken = {
    val now = Instant.now()
    SessionToken(
      token = Random.alphanumeric.take(32).mkString,
      userId = userId,
      createdAt = now,
      expiresAt = now.plus(Duration.ofMinutes(durationMinutes))
    )
  }

  override def generateApiKey(owner: String, expiresInDays: Option[Long] = None): ApiKey = {
    val now = Instant.now()
    ApiKey(
      key = "ak_" + Random.alphanumeric.take(32).mkString,
      secret = "sk_" + Random.alphanumeric.take(64).mkString,
      owner = owner,
      createdAt = now,
      expiresAt = expiresInDays.map(days => now.plus(Duration.ofDays(days)))
    )
  }
}

class SessionManager(tokenGenerator: TokenGenerator) {

  private val sessions: concurrent.Map[String, SessionToken] =
    new ConcurrentHashMap[String, SessionToken]().asScala

  private val apiKeys: concurrent.Map[String, ApiKey] =
    new ConcurrentHashMap[String, ApiKey]().asScala

  private val userSessions: concurrent.Map[String, Set[String]] =
    new ConcurrentHashMap[String, Set[String]]().asScala

  def createSession(userId: String, durationMinutes: Long = 30): SessionToken = {
    val session = tokenGenerator.generateSessionToken(userId, durationMinutes)
    sessions.put(session.token, session)
    userSessions.updateWith(userId) {
      case Some(tokens) => Some(tokens + session.token)
      case None => Some(Set(session.token))
    }
    println(s"[SessionManager] Session created for user '$userId': ${session.token}")
    session
  }

  def validateSession(token: String): Option[SessionToken] = {
    sessions.get(token).flatMap { session =>
      if (!session.isActive) {
        println(s"[SessionManager] Session '$token' is inactive.")
        None
      } else if (Instant.now().isAfter(session.expiresAt)) {
        println(s"[SessionManager] Session '$token' has expired.")
        invalidateSession(token)
        None
      } else {
        Some(session)
      }
    }
  }

  def refreshSession(token: String, additionalMinutes: Long = 30): Option[SessionToken] = {
    sessions.get(token).flatMap { session =>
      if (session.isActive && Instant.now().isBefore(session.expiresAt)) {
        val refreshed = session.copy(
          expiresAt = Instant.now().plus(Duration.ofMinutes(additionalMinutes))
        )
        sessions.put(token, refreshed)
        println(s"[SessionManager] Session '$token' refreshed.")
        Some(refreshed)
      } else {
        println(s"[SessionManager] Cannot refresh expired/inactive session '$token'.")
        None
      }
    }
  }

  def invalidateSession(token: String): Boolean = {
    sessions.get(token) match {
      case Some(session) =>
        val deactivated = session.copy(isActive = false)
        sessions.put(token, deactivated)
        userSessions.updateWith(session.userId) {
          case Some(tokens) =>
            val updated = tokens - token
            if (updated.isEmpty) None else Some(updated)
          case None => None
        }
        println(s"[SessionManager] Session '$token' invalidated.")
        true
      case None =>
        println(s"[SessionManager] Session '$token' not found.")
        false
    }
  }

  def invalidateAllUserSessions(userId: String): Int = {
    val tokens = userSessions.getOrElse(userId, Set.empty)
    tokens.foreach(invalidateSession)
    println(s"[SessionManager] All sessions for user '$userId' invalidated (${tokens.size} sessions).")
    tokens.size
  }

  def createApiKey(owner: String, expiresInDays: Option[Long] = None): ApiKey = {
    val apiKey = tokenGenerator.generateApiKey(owner, expiresInDays)
    apiKeys.put(apiKey.key, apiKey)
    println(s"[SessionManager] API key created for owner '$owner': ${apiKey.key}")
    apiKey
  }

  def validateApiKey(key: String, secret: String): Option[ApiKey] = {
    apiKeys.get(key).flatMap { apiKey =>
      if (!apiKey.isActive) {
        println(s"[SessionManager] API key '$key' is inactive.")
        None
      } else if (apiKey.secret != secret) {
        println(s"[SessionManager] API key '$key' secret mismatch.")
        None
      } else if (apiKey.expiresAt.exists(exp => Instant.now().isAfter(exp))) {
        println(s"[SessionManager] API key '$key' has expired.")
        revokeApiKey(key)
        None
      } else {
        Some(apiKey)
      }
    }
  }

  def revokeApiKey(key: String): Boolean = {
    apiKeys.get(key) match {
      case Some(apiKey) =>
        val revoked = apiKey.copy(isActive = false)
        apiKeys.put(key, revoked)
        println(s"[SessionManager] API key '$key' revoked.")
        true
      case None =>
        println(s"[SessionManager] API key '$key' not found.")
        false
    }
  }

  def getActiveSessions: List[SessionToken] = {
    val now = Instant.now()
    sessions.values.filter(s => s.isActive && now.isBefore(s.expiresAt)).toList
  }

  def getActiveApiKeys: List[ApiKey] = {
    val now = Instant.now()
    apiKeys.values.filter(k => k.isActive && k.expiresAt.forall(exp => now.isBefore(exp))).toList
  }

  def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expired = sessions.values.filter(s => now.isAfter(s.expiresAt) && s.isActive).toList
    expired.foreach(s => invalidateSession(s.token))
    println(s"[SessionManager] Cleaned up ${expired.size} expired sessions.")
    expired.size
  }

  def getSessionStats: Map[String, Any] = {
    val allSessions = sessions.values.toList
    val now = Instant.now()
    Map(
      "totalSessions" -> allSessions.size,
      "activeSessions" -> allSessions.count(s => s.isActive && now.isBefore(s.expiresAt)),
      "expiredSessions" -> allSessions.count(s => now.isAfter(s.expiresAt)),
      "inactiveSessions" -> allSessions.count(!_.isActive),
      "totalApiKeys" -> apiKeys.size,
      "activeApiKeys" -> getActiveApiKeys.size,
      "uniqueUsers" -> allSessions.map(_.userId).distinct.size
    )
  }
}

